import { api } from "@/api/axios";
import { ISmartphone } from "@/shared/types/smartphone.types";
import { Revalidate } from "next/dist/server/lib/cache-control";
import { SmartPhoneListClient } from "./SmartPhoneListClient";

export const revalidate: Revalidate = 60;

export async function SmartPhoneListResponse() {
    const response = await api.get<ISmartphone[]>("/smartphones");
    const smartphonesData = response.data;

    return <SmartPhoneListClient smartphones={smartphonesData} />;
}